/**
 * BehaviorTreeRunner.js
 * Executes JSON-based Behavior ASTs for NPCs and Enemies.
 * Replaces the old string-concatenation compiler.
 */

window.BehaviorTreeRunner = class BehaviorTreeRunner {
    constructor(game, npc) {
        this.game = game;
        this.npc = npc;
        this.logicAPI = new window.LogicRuntime(game, npc);
        this.currentAST = null;
        this.currentNode = null;
        this.isRunning = false;
        this.isPaused = false;
    }

    /**
     * Start executing a behavior AST.
     * @param {Object} ast - The behavior AST generated by BehaviorArchitect.
     */
    async start(ast) {
        if (!ast || !ast.root) {
            console.error('[BehaviorTreeRunner] Invalid AST provided');
            return;
        }

        this.currentAST = ast;
        this.isRunning = true;
        this.isPaused = false;

        console.log(`[BehaviorTreeRunner] Starting behavior: ${ast.name}`);
        
        while (this.isRunning) {
            if (!this.isPaused) {
                await this.executeNode(ast.root);
            }
            // If the behavior doesn't loop internally, it will reach here and we loop it
            // as per the original behavior_editor.js while(true) logic.
            await this.logicAPI.wait(0.1); // Small safety yield
        }
    }

    /**
     * Stop execution.
     */
    stop() {
        this.isRunning = false;
    }

    /**
     * Pause execution.
     */
    pause() {
        this.isPaused = true;
    }

    /**
     * Resume execution.
     */
    resume() {
        this.isPaused = false;
    }

    /**
     * Execute a single AST node and follow its next link.
     */
    async executeNode(node) {
        if (!node || !this.isRunning) return;

        this.currentNode = node;

        // Emit debug event for visual tracking in editor
        if (window.RedGlitchEventBus) {
            window.RedGlitchEventBus.emit('vsl:node_exec', {
                nodeId: node.id,
                entityId: this.npc.id,
                timestamp: Date.now()
            });
        }

        const d = node.data || {};
        
        try {
            // --- ACTION EXECUTION ---
            switch (node.type) {
                case 'expr_say':
                    if (this.npc.say) await this.npc.say(d.text || "...");
                    else console.log(`[NPC ${this.npc.id}] Says: ${d.text}`);
                    break;

                case 'task_wander':
                    if (this.npc.wander) await this.npc.wander(d.range || 100, d.duration || 3);
                    else await this.logicAPI.wait(d.duration || 3);
                    break;

                case 'task_goto':
                    if (this.npc.moveToPosition) await this.npc.moveToPosition(d.x || 0, d.y || 0);
                    break;

                case 'task_follow':
                    if (this.npc.canSee && this.npc.canSee(this.game.player, 200)) {
                        await this.npc.moveToPosition(this.game.player.x, this.game.player.y);
                    }
                    break;

                case 'logic_wait':
                    await this.logicAPI.wait(d.time || 1.0);
                    break;

                case 'logic_var_set':
                    this.logicAPI.setFlag(d.key || 'var', d.val || '0');
                    break;

                case 'expr_emotion':
                    if (this.npc.setEmotion) this.npc.setEmotion(d.type || 'neutral');
                    break;
                
                case 'expr_emote':
                    if (this.npc.showEmote) this.npc.showEmote(d.type || 'exclamation');
                    break;
            }

            // --- FLOW CONTROL ---
            if (node.type === 'logic_check') {
                const condition = this.logicAPI.getFlag(d.flag || 'flag');
                if (condition) {
                    await this.executeNode(node.true);
                } else {
                    await this.executeNode(node.false);
                }
            } 
            else if (node.type === 'logic_var_check') {
                const val = this.logicAPI.getFlag(d.key || 'var');
                if (val == (d.val || '0')) {
                    await this.executeNode(node.true);
                } else {
                    await this.executeNode(node.false);
                }
            }
            else if (node.type === 'sensor_see_player') {
                const canSee = this.npc.canSee ? this.npc.canSee(this.game.player, d.range || 150) : false;
                if (canSee) {
                    await this.executeNode(node.next);
                }
            }
            else if (node.type === 'sensor_near_player') {
                const dist = this.npc.getDistance ? this.npc.getDistance(this.game.player) : 999;
                if (dist < (d.range || 100)) {
                    await this.executeNode(node.next);
                }
            }
            else if (node.next) {
                // Regular sequential next node
                await this.executeNode(node.next);
            }

        } catch (error) {
            console.error(`[BehaviorTreeRunner] Error executing node ${node.type}:`, error);
        }
    }
};
